            currentMaxLenNoSwap = std::max(currentMaxLenNoSwap, i - prevIndex);
        } else {
            map_no_swap[currentDiff] = i;
        }
    }
    maxLen = std::max(maxLen, currentMaxLenNoSwap);

    // Case 2: One swap allowed
    // The maximum length L=2k is achieved if the original substring s[a...b] has an imbalance of +2 or -2.
