    // Subcase 2a: Imbalance = +2 (c0 - c1 = 2). We seek diff[b+1] = diff[a] + 2.
    // Subcase 2b: Imbalance = -2 (c0 - c1 = -2). We seek diff[a] = diff[b+1] + 2.

    std::map<int, int> map_swap;
    map_swap[0] = 0; // diff[0] = 0
    int currentMaxLenSwap = 0;

    for (int i = 1; i <= n; ++i) {
        int currentDiff = diff[i];

        // Check for Subcase 2a: diff[i] = diff[a] + 2  =>  diff[a] = diff[i] - 2
        int requiredDiffA = currentDiff - 2;
        if (map_swap.count(requiredDiffA)) {
            int a = map_swap[requiredDiffA];
            // Length is i - a
            currentMaxLenSwap = std::max(currentMaxLenSwap, i - a);
        }

        // Check for Subcase 2b: diff[i] = diff[a] - 2  =>  diff[a] = diff[i] + 2
        int requiredDiffB = currentDiff + 2;
        if (map_swap.count(requiredDiffB)) {
            int a = map_swap[requiredDiffB];
            // Length is i - a
            currentMaxLenSwap = std::max(currentMaxLenSwap, i - a);
        }

        // Store the current difference index if it's the first time we see this difference
        if (!map_swap.count(currentDiff)) {
            map_swap[currentDiff] = i;
        }
    }

    maxLen = std::max(maxLen, currentMaxLenSwap);

    return maxLen;
