    long long solve(std::string s) {
        int n = s.length();
        int maxLen = 0;

        // Calculate the difference array: diff[i] = count0[i] - count1[i] for prefix s[0...i-1]
        // diff has size n+1
        std::vector<int> diff(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            int change = (s[i] == '0' ? 1 : -1);
            diff[i + 1] = diff[i] + change;
        }

        // Case 1: No swap allowed. Find the longest substring where diff[b+1] - diff[a] = 0.
        std::map<int, int> mapNoSwap;
        mapNoSwap[0] = -1; 
        int currentMaxLenNoSwap = 0;

        for (int i = 0; i <= n; ++i) {
            int currentDiff = diff[i];
            if (mapNoSwap.count(currentDiff)) {
